update vocabularies set description = 'Chỉ các tổ chức, cơ quan có quyền lực quản lý và thực thi pháp luật. Thường dùng ở dạng số nhiều "the authorities".' where id = '018a7251-f485-4718-9bd7-d04ac44c7bcc';
update vocabularies set description = 'Cố ý né tránh điều gì đó. Khác với "prevent" (ngăn chặn từ bên ngoài) — avoid là tự mình tránh không làm hoặc không đến gần.' where id = '4bcba0b4-881e-47f4-82eb-8767c726a266';
update vocabularies set description = 'Dạng hiện tại phân từ của "cause", dùng khi nói đến nguyên nhân đang trực tiếp tạo ra hậu quả. Thường đi với danh từ chỉ tác hại: causing damage, causing floods.' where id = '94711328-be28-48fd-917b-45a5e065d9c9';
update vocabularies set description = 'Chỉ toàn bộ vùng đất liền tiếp giáp biển. Khác với "beach" (bãi cát cụ thể) — coast chỉ dải ven biển rộng hơn.' where id = '5ccfa640-05f1-4047-bf28-750e997e2f34';
update vocabularies set description = 'Nhóm người cùng thực hiện một nhiệm vụ. Trong tình huống khẩn cấp thường gặp: rescue crews (đội cứu hộ), emergency crews (đội ứng cứu).' where id = '3a89ffbe-91e4-44e1-8729-dc5daa7ce663';
update vocabularies set description = 'Thiệt hại về vật chất hoặc tài sản. Khác với "injury" (chấn thương người) — damage dùng cho đồ vật và tài sản, không dùng cho người.' where id = '66a7a3a4-f383-4fdf-a4b9-f15c09c84efe';
update vocabularies set description = 'Tính từ chỉ hướng hoặc vùng phía đông. Viết hoa khi là tên riêng địa lý (Eastern Europe), viết thường khi chỉ hướng chung.' where id = '4bbb7028-6eb6-4825-b7e8-ad677cd572f6';
update vocabularies set description = 'Năng lượng điện nói chung. Khác với "power" — electricity nhấn mạnh bản chất vật lý của điện, power nhấn mạnh nguồn cung cấp năng lượng có thể bị mất.' where id = '3f983c7f-2466-41ec-a6ed-a135c3fdd4ae';
update vocabularies set description = 'Tình huống nguy hiểm đòi hỏi hành động ngay lập tức. Thường gặp trong: emergency services, state of emergency, declare an emergency.' where id = '807c8f29-b214-4b5c-9825-f113b876e9e7';
update vocabularies set description = 'Trạng từ/tính từ chỉ vị trí bên trong tòa nhà. Trái nghĩa với "outdoors". Thường dùng khi khuyên người ở trong nhà để tránh nguy hiểm.' where id = '1d7b9b8b-8758-470f-af5e-9597d1962cb1';
update vocabularies set description = 'Sự gián đoạn dịch vụ, đặc biệt là mất điện (power outage). Dùng ở dạng số nhiều khi nói đến nhiều lần mất điện ở nhiều khu vực.' where id = '7682163a-ad9f-4a13-8fd3-5a1f3dc9cb74';
update vocabularies set description = 'Trong ngữ cảnh thiên tai, "power" chỉ nguồn điện. Khác với "electricity" — power nhấn mạnh nguồn cung cấp và thường dùng trong "power is out / power cut".' where id = '008a9469-4405-4c22-99d8-5d4b69127888';
update vocabularies set description = 'Mô tả sức mạnh lớn, tác động mạnh. Trong ngữ cảnh thời tiết, dùng cho bão và gió. Mạnh hơn "strong" — powerful nhấn mạnh tác động và uy lực.' where id = '601c3d81-e5f6-42ae-8af4-b6be9a700680';
update vocabularies set description = 'Dạng số nhiều của "road", chỉ các tuyến đường dành cho phương tiện. Dùng để nói về hệ thống giao thông nói chung: roads are flooded, roads are closed.' where id = '5622d52a-b960-4f1a-ad1a-cd147591b36b';
update vocabularies set description = 'Hoàn cảnh hay trạng thái hiện tại của một vấn đề. Thường dùng trong: the current situation, assess the situation, dangerous situation.' where id = '9166b629-1dfd-4934-964f-31c79a9ea2e5';
update vocabularies set description = 'Khi dùng làm mệnh lệnh, "stay" mang nghĩa mạnh hơn "remain". Thường đi với giới từ chỉ nơi chốn: stay indoors, stay away from, stay safe.' where id = 'c2efca6f-fd59-4eee-b7cb-fc9346204e06';
update vocabularies set description = 'Hiện tượng thời tiết dữ dội với mưa và gió mạnh. Phân biệt: storm (bão thông thường), hurricane (bão nhiệt đới mạnh ở Đại Tây Dương), typhoon (bão ở Thái Bình Dương).' where id = '9017d59b-bab0-4f00-af82-bc2f5e186ade';
update vocabularies set description = 'Quá khứ của "sweep". Trong ngữ cảnh thiên tai mang nghĩa bị cuốn trôi hoặc tàn phá. Thường gặp: swept away by floods (bị lũ cuốn trôi), swept through the area (quét qua khu vực).' where id = 'dbe05605-4978-45be-9279-b86378ce941a';
update vocabularies set description = 'Khi dùng như danh từ không đếm được, "travel" chỉ hoạt động đi lại nói chung. Gặp trong cảnh báo thiên tai: avoid unnecessary travel, travel disruption.' where id = '04f7ed4f-c6c3-4766-aae9-ab98fe3142a2';
update vocabularies set description = '"Stay tuned" là cụm cố định nghĩa là "tiếp tục theo dõi". Xuất phát từ lĩnh vực phát thanh/truyền hình, nay dùng rộng khi yêu cầu người nghe chú ý cập nhật.' where id = 'b65b59db-8c35-4cee-9463-2aac4cd80bae';
update vocabularies set description = 'Tính từ chỉ điều không cần thiết phải làm. Trong cảnh báo thiên tai, "avoid unnecessary travel" nghĩa là không đi lại trừ khi thực sự cần thiết.' where id = '1fd3a407-b827-4601-95e0-2de53cde342b';
update vocabularies set description = 'Hiện tại phân từ của "urge", mang nghĩa khuyến cáo mạnh hơn "advising". Thường dùng trong tình huống khẩn cấp khi cơ quan chức năng ra khuyến cáo chính thức.' where id = 'cb23e502-89fa-4cc1-bf97-99207183f235';
update vocabularies set description = 'Tính từ mô tả phạm vi ảnh hưởng rất rộng. Thường đi với: widespread damage (thiệt hại trên diện rộng), widespread flooding, widespread power outages.' where id = '984d9d89-a7ab-4e04-ae54-a16b81ec9464';
